import React from 'react';

const styles = {
  nav: {
    background: '#fff',
    borderBottom: '1px solid #e5e7eb',
    padding: '0 32px',
    height: 60,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
    position: 'sticky',
    top: 0,
    zIndex: 100,
    boxShadow: '0 1px 3px rgba(0,0,0,0.07)',
  },
  logo: {
    display: 'flex',
    alignItems: 'center',
    gap: 10,
    fontWeight: 700,
    fontSize: 18,
    color: '#1a1a2e',
  },
  logoIcon: {
    width: 32, height: 32,
    background: '#2563eb',
    borderRadius: 8,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    color: '#fff',
    fontSize: 16,
  },
  badge: {
    display: 'flex',
    alignItems: 'center',
    gap: 6,
    fontSize: 12,
    color: '#16a34a',
    background: '#f0fdf4',
    border: '1px solid #bbf7d0',
    padding: '4px 12px',
    borderRadius: 20,
  },
  dot: {
    width: 7, height: 7,
    background: '#16a34a',
    borderRadius: '50%',
    animation: 'pulse 2s infinite',
  },
};

export default function Navbar({ apiOnline }) {
  return (
    <nav style={styles.nav}>
      <div style={styles.logo}>
        <div style={styles.logoIcon}>🎯</div>
        <span>HireSense</span>
        <span style={{ fontWeight: 400, color: '#6b7280', fontSize: 13 }}>AI Resume Screening</span>
      </div>
      <div style={styles.badge}>
        <div style={{ ...styles.dot, background: apiOnline ? '#16a34a' : '#dc2626' }} />
        {apiOnline ? 'API Connected' : 'API Offline'}
      </div>
    </nav>
  );
}
